"use client";
import React, { useMemo, useRef } from 'react';
import dynamic from 'next/dynamic';
import 'react-quill-new/dist/quill.snow.css';

const ReactQuill = dynamic(async () => {
  const { default: RQ } = await import('react-quill-new');
  return ({ forwardedRef, ...props }: any) => <RQ ref={forwardedRef} {...props} />;
}, { ssr: false });

export default function Editor({ value, onChange }: any) {
  const quillRef = useRef<any>(null);

  // 이미지를 서버에 업로드하는 함수
  const imageHandler = () => {
    const input = document.createElement('input');
    input.setAttribute('type', 'file');
    input.setAttribute('accept', 'image/*');
    input.click();

    input.onchange = async () => {
      const file = input.files?.[0];
      if (file) {
        const formData = new FormData();
        formData.append('file', file);

        try {
          // 백엔드의 파일 업로드 API 호출 (아래 Step 2에서 작성)
          const res = await fetch('http://localhost:8080/api/board/upload', {
            method: 'POST',
            body: formData,
          });
          const imgUrl = await res.text(); // 서버에서 저장된 파일명 혹은 URL 반환

          const quill = quillRef.current.getEditor();
          const range = quill.getSelection();
          // 에디터에 Base64 대신 서버 경로 삽입
          quill.insertEmbed(range.index, 'image', `/img/${imgUrl}`);
        } catch (error) {
          console.error('이미지 업로드 실패:', error);
        }
      }
    };
  };

  const modules = useMemo(() => ({
    toolbar: {
      container: [
        [{ header: [1, 2, false] }],
        ['bold', 'italic', 'underline'],
        ['link', 'image'],
      ],
      handlers: { image: imageHandler }, // 이미지 버튼 클릭 시 커스텀 핸들러 실행
    },
  }), []);

  return (
    <div style={{ height: '400px', marginBottom: '50px' }}>
      <ReactQuill
        forwardedRef={quillRef}
        theme="snow"
        value={value}
        onChange={onChange}
        modules={modules}
        style={{ height: '350px' }}
      />
    </div>
  );
}